INSERT INTO exercise_v2_compat_activities
  (pair_id, activity_order, activity_name, activity_emoji, description, tip_a_invites_b, tip_b_invites_a)
SELECT
  id,
  1,
  'クロスフィット体験',
  '🏋️',
  'GPADにとって、クラス全員が同じその日の決められたメニューに取り組む一体感が独特の連帯感を生みます。隣の人が頑張っていると自分も頑張れる環境です。また、メニューの内容・回数・タイムを記録して前回と比較する明確な指標があります。スキルアップの方向性も明確です。

SPTCにとっては、自分の記録と向き合う時間があります。ワークアウトの内容は決まっているので、自分のペースで取り組めます。また、メニューの内容・回数・タイムを記録して前回と比較する明確な指標があります。スキルアップの方向性も明確です。

GPADが場の活気を生み出し、SPTCがそのエネルギーを自分のペースで受け取るという自然な役割分担ができます。',
  'SPTCは義務感や予定の重さを感じやすいので、「気が向いたら」「体験だけでいいから」という軽い誘い方がうまくいきやすいです。 また、SPTCは「失敗したらどうしよう」という気持ちを持ちやすいです。「うまくできなくていいよ」「私も初めてだよ」という一言が安心感を与えます。 ジムの体験クラスに誘うときは、その日のメニューが決まっていること・自分の体力に合わせて強さを変えられることを伝えると安心です。',
  'GPADは一緒に動く体験の共有に喜びを感じます。「一緒に行こう」という言葉と具体的な日時・場所を伝えることで、相手が期待感を持って準備できます。 また、GPADは「大丈夫、行けるよ」という自信を持ちやすいタイプです。あなたが感じている不安を正直に伝えると、自然にサポートしてくれます。 誘われたら、腰痛や膝の痛み、運動習慣がほぼないことを正直に伝え、無理な重量は使わないと約束してもらうとよいです。'
FROM exercise_v2_compat_pairs WHERE type_a = 'GPAD' AND type_b = 'SPTC'
ON CONFLICT (pair_id, activity_order) DO UPDATE
  SET activity_name = EXCLUDED.activity_name,
      activity_emoji = EXCLUDED.activity_emoji,
      description = EXCLUDED.description,
      tip_a_invites_b = EXCLUDED.tip_a_invites_b,
      tip_b_invites_a = EXCLUDED.tip_b_invites_a;

