INSERT INTO exercise_v2_compat_activities
  (pair_id, activity_order, activity_name, activity_emoji, description, tip_a_invites_b, tip_b_invites_a)
SELECT
  id,
  1,
  '太極拳・気功体験',
  '☯️',
  'SPACにとって、完璧な動きができなくてもその場で続けられます。先生の動きを大まかに真似するだけで成立します。また、自分の呼吸とゆっくりした動きに集中する、内向きの静かな活動です。周囲に溶け込みながら自分の世界に入れます。

SPTCにとっては、間違えても笑われない雰囲気があり、指導員の丁寧な指導が「正しくできているか」という心配を和らげてくれます。また、自分の呼吸とゆっくりした動きに集中する、内向きの静かな活動です。周囲に溶け込みながら自分の世界に入れます。

SPACの「大丈夫、気にしなくていいよ」という姿勢がSPTCにとっての安心材料になります。SPTCが深く感じ取った気づきを伝えることで活動がより豊かになります。',
  'SPTCは「失敗したらどうしよう」という気持ちを持ちやすいです。「うまくできなくていいよ」「私も初めてだよ」という一言が安心感を与えます。 太極拳や気功に誘うときは、ゆっくりした動きであること・武術の試合ではないことを伝えると、高齢や運動不足の相手にも伝わりやすいです。',
  'SPACは「大丈夫、行けるよ」という自信を持ちやすいタイプです。あなたが感じている不安を正直に伝えると、自然にサポートしてくれます。 誘われたら、膝の曲げ伸ばしの不安や立ちっぱなしがつらいかを伝え、椅子に座ってできるかも聞いておくとよいです。'
FROM exercise_v2_compat_pairs WHERE type_a = 'SPAC' AND type_b = 'SPTC'
ON CONFLICT (pair_id, activity_order) DO UPDATE
  SET activity_name = EXCLUDED.activity_name,
      activity_emoji = EXCLUDED.activity_emoji,
      description = EXCLUDED.description,
      tip_a_invites_b = EXCLUDED.tip_a_invites_b,
      tip_b_invites_a = EXCLUDED.tip_b_invites_a;

